From 3481af304449c3b306d769af3f7f2e40f58d3170 Mon Sep 17 00:00:00 2001
From: baur <baurzhansahariev@gmail.com>
Date: Wed, 13 Nov 2024 19:02:36 +0100
Subject: [PATCH] Use floatValue and doubleValue to validate values

We don't need intermediate conversion to the BigInteger
as it can lead to heavy computations of pow(BigInteger.TEN, big_exponent)
causing queries to hang.
---
 docs/appendices/release-notes/5.9.3.rst             |  5 +++++
 server/src/main/java/io/crate/types/DoubleType.java | 13 ++++++++-----
 server/src/main/java/io/crate/types/FloatType.java  | 13 ++++++++-----
 .../java/io/crate/planner/SelectPlannerTest.java    | 13 +++++++++++++
 4 files changed, 34 insertions(+), 10 deletions(-)

diff --git a/docs/appendices/release-notes/5.9.3.rst b/docs/appendices/release-notes/5.9.3.rst
index 7fb94f8793..db490b5c1d 100644
--- a/docs/appendices/release-notes/5.9.3.rst
+++ b/docs/appendices/release-notes/5.9.3.rst
@@ -148,3 +148,8 @@ Fixes
   ``ORDER BY`` expression contained a nested function. For example::

     SELECT * FROM t ORDER BY LEFT(txt_col, 1) = ANY(['a']);
+
+- Fixed an issue that caused casting values of the ``NUMERIC`` type to the
+  ``float`` or ``double`` types to hang. For example::
+
+    SELECT exp(-1110102730.1852759636)::float;
diff --git a/server/src/main/java/io/crate/types/DoubleType.java b/server/src/main/java/io/crate/types/DoubleType.java
index 1c03549eec..3929a383af 100644
